);

wire [N-1:0] upper_half;
wire [N-1:0] lower_half;
priority_encoder #(.N(N/2),.M(log2(N/2))) upper_pe (.in(input_signal[N-1:N/2]),.out(upper_half));
priority_encoder #(.N(N/2),.M(log2(N/2))) lower_pe (.in(input_signal[N/2-1:0]),.out(lower_half));
assign out = (input_signal[N-1] == 1)? upper_half : lower_half;
assign out_upper_half = upper_half[N-2:0];
assign out_lower_half = lower_half[N-2:0];

endmodule

output.rtl/Attenuator.sv:
module Attenuator (
    input        clk,
    input        reset,
    input  [4:0] data,
    output reg   ATTN_CLK,
    output reg   ATTN_DATA,
    output reg   ATTN_LE
);

// Internal Signals
reg        clk_div2;
reg  [1:0] current_state, next_state;
reg  [4:0] shift_reg;
reg  [2:0] bit_count;
reg  [4:0] old_data;

// Parameters for FSM States
localparam IDLE  = 2'b00,
           LOAD  = 2'b01,
           SHIFT = 2'b10,
           LATCH = 2'b11;

// Reset Condition
always @(posedge clk or posedge reset) begin
    if (reset) begin
        clk_div2 <= 1'b0;
        current_state <= IDLE;
        ATTN_CLK      <= 1'b0;
        ATTN_DATA     <= 1'b0;
        ATTN_LE       <= 1'b0;
        shift_reg     <= 5'b00000;
        bit_count     <= 3'd0;
        old_data      <= 5'b00000;
    end else begin
        case(current_state)
            IDLE: begin
                if (data!= old_data) begin
                    next_state = LOAD;
                end else begin
                    next_state = current_state;
                end
            end
            LOAD: begin
                next_state = SHIFT;
                shift_reg <= data;
                bit_count <= 3'd0;
            end
            SHIFT: begin
                if (bit_count == 3'd4) begin
                    next_state = LATCH;
                end else begin
                    next_state = SHIFT;
                    bit_count <= bit_count + 3'd1;
                end
            end
            LATCH: begin
                next_state = IDLE;
                ATTN_LE   <= 1'b1;
            end
            default: next_state = IDLE;
        endcase

        current_state <= next_state;

        if (next_state == IDLE && current_state!= IDLE) begin
            ATTN_CLK <= 1'b0;
            ATTN_DATA <= 1'b0;
            ATTN_LE   <= 1'b0;
        end else begin
            ATTN_CLK <= ~clk_div2;
            ATTN_DATA <= shift_reg[0];

            if (bit_count == 3'd4) begin
                ATTN_LE <= 1'b1;
            end else begin
                ATTN_LE <= 1'b0;
            end
        end

        clk_div2 <= ~clk_div2;
    end
end

