module bcd_to_excess_3(
  input [3:0] bcd,
  output reg [3:0] excess3,
  output reg error
);

  always @* begin
    if ((bcd >= 10) && (bcd <= 15)) begin
      // Invalid BCD input
      excess3 = 4'b0;
      error = 1;
    end else begin
      // Valid BCD input
      excess3 = bcd + 3;
      error = 0;
    end
  end

endmodule

