module pseudo_lru_nmru_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
) (
    input wire clock,
    input wire reset,
    input wire [$clog2(NINDEXES)-1:0] index,
    input wire [$clog2(NWAYS)-1:0] way_select,
    input wire access,
    input wire hit,
    output reg [$clog2(NWAYS)-1:0] way_replace
);

reg [NWAYS-1:0][NINDEXES-1:0] recency;

integer reset_counter;

always @(posedge clock or posedge reset) begin
    if (reset) begin
        for (reset_counter = 0; reset_counter < NINDEXES; reset_counter = reset_counter + 1) begin
            recency[reset_counter] <= {NWAYS{1'b0}};
        end
    end else begin
        if (access && hit) begin
            recency[index][way_select] <= 1'b1;
        end

        // Handle NMRU policy when multiple bits are zero
        integer i;
        for (i = 0; i < NINDEXES; i = i + 1) begin
            if (!access ||!hit) begin
                if (recency[i][way_select] == 1'b0) begin
                    way_replace <= i;
                    break;
                end
            end
        end
    end
end

endmodule

output.rtl/lru_counter_policy.sv:
module lru_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    reg [(NWAYS * $clog2(NWAYS))-1:0] recency [NINDEXES-1:0];

    wire lru_slot_found;
    wire [$clog2(NWAYS)-1:0] lru_slot;

    integer i, n;

    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] <= $clog2(NWAYS)'(n);
                end
            end
        end else begin
            // Recency Update Logic
            if (access &&!hit) begin
                for (i = 0; i < NINDEXES; i = i + 1) begin
                    recency[i][(way_select * $clog2(NWAYS)) +: $clog2(NWAYS)] <= $clog2(NWAYS)'(NWAYS-1);
                    for (n = 0; n < NWAYS; n = n + 1) begin
                        if (n!= way_select && recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] > recency[i][(way_select * $clog2(NWAYS)) +: $clog2(NWAY)]) begin
                            recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAY)] <= recency[i][(way_select * $clog2(NWAYS)) +: $clog2(NWAY)] - 1;
                        end
                    end
                end
            end

            // Replacement Logic
            lru_slot_found <= (way_select == lru_slot);
            if (hit && lru_slot_found) begin
                way_replace <= lru_slot;
            end
        end
    end

endmodule

