module data_width_converter(
  input  wire logic clk,
  input  wire logic reset,
  input  wire [31:0] data_in,
  input  wire logic data_valid,
  output      logic o_data_out_valid,
  output reg [127:0] o_data_out
);

  // Define registers and signals
  reg [31:0] data_reg [3:0];
  reg [2:0] counter;
  reg valid_reg;

  // Concatenate four 32-bit inputs into a single 128-bit output
  always @(posedge clk) begin
    if (reset) begin
      data_reg <= 4'h0;
      counter <= 0;
      valid_reg <= 0;
    end else if (counter < 4 && data_valid) begin
      data_reg[counter] <= data_in;
      counter <= counter + 1;
    end else if (counter == 4) begin
      o_data_out <= {data_reg[3], data_reg[2], data_reg[1], data_reg[0]};
      o_data_out_valid <= valid_reg;
      valid_reg <= 0;
      counter <= 0;
    end else if (counter > 4) begin
      valid_reg <= 0;
      counter <= 0;
    end
  end

endmodule

output.rtl/dbi_enc.sv:
module dbi_enc #(
    parameter N = 40
)(
    input wire [N-1:0] data_in,
    input wire clk,
    input wire rst_n,
    output logic [N-1:0] data_out,
    output logic [1:0] dbi_cntrl
);

    logic [N-1:0] prev_data;
    logic [N-1:0] inv_group_0, inv_group_1;
    logic [N-1:0] group_0, group_1;
    logic [1:0] cntrl;

    // Split data into 2 groups
    assign {group_0, group_1} = data_in;

    // Compare groups with their previous values
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            prev_data <= '0;
        end else begin
            prev_data <= data_in;
        end
    end

    // Calculate difference between groups and previous data
    always @(*) begin
        // Invert group 0 if more than 10 bits differ
        for (int i=0; i<N; i++) begin
            if ((group_0 & ~(prev_data >> i)) | (prev_data & ~(group_0 >> i))) begin
                inv_group_0[i] = ~group_0[i];
            end else begin
                inv_group_0[i] = group_0[i];
            end
        end

        // Invert group 1 if more than 10 bits differ
        for (int i=0; i<N; i++) begin
            if ((group_1 & ~(prev_data >> i)) | (prev_data & ~(group_1 >> i))) begin
                inv_group_1[i] = ~group_1[i];
            end else begin
                inv_group_1[i] = group_1[i];
            end
        end
    end

    // Generate dbi_cntrl based on bitwise differences
    assign cntrl[0] = (inv_group_0!= prev_data[19:0])? 1'b1 : 1'b0;
    assign cntrl[1] = (inv_group_1!= prev_data[39:20])? 1'b1 : 1'b0;

    // Generate data_out based on dbi_cntrl
    assign data_out = (dbi_cntrl == 2'b00)? (group_1 << 20) | group_0 : (inv_group_0 << 20) | inv_group_1;

endmodule

output.rtl/dbi_dec.sv:
module dbi_dec (
   // Inputs
   input  wire        rst_n,     // Asynchronous reset
   input  wire        clk,       // Clock
   input  wire [39:0] data_in,   // Data input before DBI decoder logic
   input  wire [1:0]  dbi_cntrl, // Indicate data inversion enabled for each group 
   // Outputs
   output wire [39:0] data_out   // Output data after DBI logic
   );

   // Splitting the incoming data into two 20-bit groups:
   wire [19:0] group_1;
   wire [19:0] group_0;

   assign {group_1, group_0} = data_in[39:18];

   // Decoding the data based on dbi_cntrl:
   wire [19:0] inv_group_1;
   wire [19:0] inv_group_0;

   always @(*) begin
      if (dbi_cntrl == 2'b00) begin
         inv_group_1 = ~group_1;
         inv_group_0 = ~group_0;
      end else begin
         inv_group_1 = group_1;
         inv_group_0 = group_0;
      end
   end

   // Combining the decoded groups to generate the final output:
   assign data_out = {inv_group_1, inv_group_0};

endmodule

