        .q     (valid)
    );

endmodule

////////////////////////////////////////////////
// Pre-scaling (Prescaling) Module
////////////////////////////////////////////////
module pre_scaler (
    input  logic [17:0] a,  // unsigned divisor
    input  logic [17:0] c,  // unsigned dividend
    output logic [17:0] b,  // prescaled divisor
    output logic [17:0] d   // prescaled dividend
);
    // For simplicity, if 'a' is large, we shift until it is < 1.0 in Q9.9 format
    // That means the integer bits of 'a' must be 0. We find how many leading bits
    // we need to shift out.

    always_comb begin : SHIFT_LOGIC
        // 'a' has 18 bits in total, where the top 9 bits are integer, bottom 9 bits are fractional.
        // We want the integer part of 'a' to be 0 => 'a[17:9]' should be zero after shifting.

        if (a[17]) begin
            b = a >> 8;
            d = c >> 8;
        end
        else if (a[16]) begin
            b = a >> 7;
            d = c >> 7;
        end
        else if (a[15]) begin
            b = a >> 6;
            d = c >> 6;
        end
        else if (a[14]) begin
            b = a >> 5;
            d = c >> 5;
        end
        else if (a[13]) begin
            b = a >> 4;
            d = c >> 4;
        end
        else if (a[12]) begin
            b = a >> 3;
            d = c >> 3;
        end
        else if (a[11]) begin
            b = a >> 2;
            d = c >> 2;
        end
        else if (a[10]) begin
            b = a >> 1;
            d = c >> 1;
        end
        else begin
            b = a;
            d = c;
        end
    end
endmodule

