         end
      end else begin : DYNAMIC_COEFFS
         reg [LGNCOEF-1:0] tap_wr_idx;
         initial tap_wr_idx = 0;
         always @(posedge i_clk)
            if (i_reset)
                tap_wr_idx <= 0;
            else if (i_tap_wr)
                tap_wr_idx <= tap_wr_idx + 1'b1;
         always @(posedge i_clk)
            if (i_tap_wr)
                coef_mem_messy[tap_wr_idx] <= i_tap;
      end
    endgenerate


    initial write_idx = 0;
    always @(posedge i_clk) begin
        if (i_ce)
            write_idx = write_idx + 1;  
    end

    always @(posedge i_clk)
      if (i_ce) begin
         dmem1_messy[write_idx] <= i_sample;
         dmem2_messy[write_idx] <= mid_sample_messy;
      end

    always @(posedge i_clk)
    begin
      if (i_reset)
         mid_sample_messy <= 0;
      else if (i_ce)
         mid_sample_messy <= sample_left;
    end

    assign remaining_taps = QTRTAPS - tap_idx;
    assign last_tap_warn = (remaining_taps <= 1);
    assign last_data_warn = (QTRTAPS - tap_idx <= 2);


    initial messy_flag = 4'b0;
    always @(posedge i_clk) begin
      if (i_reset)
        messy_flag[0] <= 1'b0;
      else if (i_ce)
        messy_flag[0] <= 1'b1;
      else if (messy_flag[0] && !last_tap_warn)
        messy_flag[0] <= 1'b1;
      else if (!clk_en)
        messy_flag[0] <= 1'b0;
    end

    always @(posedge i_clk)
      if (i_reset)
         messy_flag[3:1] <= 3'b0;
      else
         messy_flag[3:1] <= { messy_flag[2:1], (clk_en || (messy_flag[0] && !last_tap_warn)) };


    initial begin
      left_idx = 0;
      right_idx = 0;
    end

    always @(posedge i_clk) begin
      if (i_reset) begin
        left_idx <= 0;
        right_idx <= 0;
      end else if (i_ce) begin
        left_idx <= write_idx;
        right_idx <= write_idx - (HALFTAPS[LGNMEM-1:0]) + 1;
      end else if (clk_en || !last_data_warn) begin
        left_idx <= left_idx - 2;
        right_idx <= right_idx + 2;
      end
    end


    initial tap_idx = 0;
    always @(posedge i_clk) begin
      if (i_reset)
         tap_idx <= 0;
      else if (clk_en)
         tap_idx <= 0;
      else if (!last_tap_warn)
         tap_idx <= tap_idx + 1;
    end


    initial clk_en = 1'b0;
    always @(posedge i_clk) begin
      clk_en <= (i_ce && !i_reset);
    end


    initial begin
        sample_left  = 0;
        sample_right = 0;
    end

    always @(posedge i_clk) begin
      sample_left  <= dmem1_messy[left_idx];
      sample_right <= dmem2_messy[right_idx];
    end

    // --- Data Enable Update ---
    initial data_en = 1'b0;
    always @(posedge i_clk)
       data_en <= (clk_en && !i_reset);

    // --- Coefficient Read and Data Sum Computation ---
    reg [TW-1:0] current_coef;
    initial current_coef = 0;
    always @(posedge i_clk)
       current_coef <= coef_mem_messy[tap_idx[LGNCOEF-1:0]];

    initial sum_data = 0;
    always @(posedge i_clk) begin
      if (i_reset)
         sum_data <= 0;
      else if (OPT_HILBERT)
         sum_data <= sample_left - sample_right;
      else
         sum_data <= sample_left + sample_right;
    end

    // --- Summation Enable ---
    initial sum_en = 1'b0;
    always @(posedge i_clk)
       sum_en <= (data_en && !i_reset);

    // --- Multiply Operation ---
    initial mult_result = 0;
    always @(posedge i_clk)
       mult_result <= current_coef * sum_data;

       wire [OW-1:0] mid_prod;
    generate
      if (OPT_HILBERT) begin : NO_MIDPOINT
         assign mid_prod = 0;
      end else begin : GEN_MIDPOINT
         reg [OW-1:0] mid_prod_reg;
         initial mid_prod_reg = 0;
         always @(posedge i_clk) begin
            if (i_reset)
               mid_prod_reg <= 0;
            else if (clk_en)
               mid_prod_reg <= { {(OW-IW-TW+1){mid_sample_messy[IW-1]}}, 
                                  mid_sample_messy, {(TW-1){1'b0}} }
                              - { {(OW-IW){mid_sample_messy[IW-1]}}, 
                                  mid_sample_messy };
         end
         assign mid_prod = mid_prod_reg;
      end
    endgenerate

    // --- Accumulation ---
    initial acc_result = 0;
    always @(posedge i_clk) begin
      if (i_reset)
         acc_result <= 0;
      else if (sum_en)
         acc_result <= mid_prod;
      else if (messy_flag[3])
         acc_result <= acc_result + { {(OW-(IW+TW)){mult_result[IW+TW-1]}}, mult_result };
    end

    // --- Output Assignments ---
    initial o_result = 0;
    always @(posedge i_clk)
       if (sum_en)
          o_result <= acc_result;

    // --- Output Clock Enable Update ---
    initial o_ce = 1'b0;
    always @(posedge i_clk)
       o_ce <= (sum_en && !i_reset);

endmodule

output.rtl/hamming_code_tx_for_4bit.sv:
module hamming_code_tx_for_4bit(input logic [3:0] data_in, output logic [7:0] data_out);

   assign data_out[0] = 1'b0;
   assign data_out[1] = ^(data_in[0] & data_in[1] & data_in[3]);
   assign data_out[2] = ^(data_in[0] & data_in[2] & data_in[3]);
   assign data_out[4] = ^(data_in[1] & data_in[2] & data_in[3]);
   assign data_out[3:5] = {data_in[0], data_in[1], data_in[2]};

endmodule

output.rtl/hamming_code_receiver.sv:
module hamming_code_receiver #(parameter PARITY_BITS=3, parameter DATA_BITS=4);

    // Define inputs and outputs
    input  wire logic [DATA_BITS+PARITY_BITS-1:0] data_in;
    output      logic [DATA_BITS-1:0]         data_out;

    // Define internal signals
    logic [DATA_BITS-1:0]            syndrome;
    logic [PARITY_BITS-1:0]        error_detector;
    logic [DATA_BITS-1:0]            corrected_data;

    // Even parity error detection
    always_comb begin
        error_detector = ^(data_in & {{DATA_BITS-PARITY_BITS{1'b0}}, 1'b1});

        // Calculate syndrome bits
        syndrome = data_in & {~{error_detector}, ~{error_detector}};
    end

    // Error indication by syndrome
    always_comb begin
        if(syndrome == 3'b000) begin
            data_out = data_in;
        end else begin
            data_out = data_in ^ ((syndrome >> 1) & {{DATA_BITS-PARITY_BITS{1'b0}}, 1'b1});
        end
    end

endmodule

input.rtl/hamming_tx.sv:
module hamming_code_tx_for_4bit( 
  input[3:0] data_in,
  output[7:0] data_out
);
  assign data_out[0] = 1'b0;
  assign data_out[1] = data_in[0] ^ data_in[1] ^ data_in[3]; // 2^0
  assign data_out[2] = data_in[0] ^ data_in[2] ^ data_in[3]; // 2^1
  assign data_out[3] = data_in[0];
  assign data_out[4] = data_in[1] ^ data_in[2] ^ data_in[3]; // 2^2
  assign data_out[5] = data_in[1];
  assign data_out[6] = data_in[2];
  assign data_out[7] = data_in[3];
endmodule

output.rtl/hamming_tx.sv:
module hamming_code_tx_for_4bit( 
  input[3:0] data_in,
  output[7:0] data_out
);
  assign data_out[0] = 1'b0;
  assign data_out[1] = data_in[0] ^ data_in[1] ^ data_in[3]; // 2^0
  assign data_out[2] = data_in[0] ^ data_in[2] ^ data_in[3]; // 2^1
  assign data_out[3] = data_in[0];
  assign data_out[4] = data_in[1] ^ data_in[2] ^ data_in[3]; // 2^2
  assign data_out[5] = data_in[1];
  assign data_out[6] = data_in[2];
  assign data_out[7] = data_in[3];
endmodule

input.rtl/hamming_rx.sv:
module hamming_code_receiver (
  input[7:0] data_in,
  output [3:0] data_out
);

  wire c1,c2,c3,error;
  reg[7:0] correct_data;


  assign c3 =  data_in[1] ^ data_in[3] ^ data_in[5] ^ data_in[7];
  assign c2 =  data_in[2] ^ data_in[3] ^ data_in[6] ^ data_in[7];
  assign c1 =  data_in[4] ^ data_in[5] ^ data_in[6] ^ data_in[7];

  assign error = ({c3,c2,c1}==3'b000) ? 1'b0 : 1'b1;

  always@(*)
  begin
    correct_data = 0;
    if(error)
    begin
      correct_data             = data_in;
      correct_data[{c1,c2,c3}] = ~correct_data[{c1,c2,c3}];
    end
    else
    begin
      correct_data             = data_in;
    end
  end

 assign data_out = {correct_data[7],correct_data[6],correct_data[5],correct_data[3]};

endmodule

output.rtl/hamming_rx.sv:
module hamming_rx #(parameter DATA_WIDTH=4, parameter PARITY_BIT=3, parameter ENCODED_DATA=8, parameter ENCODED_DATA_BIT=3) (
  input [Encoded_Data-1:0] data_in,
  output [DATA_WIDTH-1:0] data_out
);

  wire [PARITY_BIT-1:0] parity;
  wire [PARITY_BIT-1:0] parity_check;
  wire [DATA_WIDTH-1:0] corrected_data;

  always @*
  begin
    // Initialization
    parity <= 0;

    // Error Detection Using Even Parity Logic
    for (int i=0; i<PARITY_BIT; i++)
    begin
      parity[i] = |(data_in & {{1{~parity_check[i]}}, 1'b1});
    }

    // Error Correction
    parity_check = (parity == 0)? 0 : 1;

    // Output Assignment
    corrected_data = data_in;
    corrected_data[{PARITY_BIT-1:0}] = ~parity_check;
    data_out = corrected_data[DATA_WIDTH-1:0];

  end

endmodule

output.rtl/hamming_tx.sv:
module hamming_tx #(
    //Input parameters:
    parameter DATA_WIDTH       = 4,
    parameter PARITY_BIT       = 3,
    parameter ENCODED_DATA     = PARITY_BIT + DATA_WIDTH + 1,
    parameter ENCODED_DATA_BIT = $clog2(ENCODED_DATA)
)(
    input  [DATA_WIDTH-1:0]    data_in,
    output [TOTAL_ENCODED-1:0] data_out
);

    localparam NUM_MODULES      = DATA_WIDTH / PARTY_BIT;
    localparam TOTAL_ENCODED  = NUM_MODULES * ENCODED_DATA;

    wire [TOTAL_ENCODED-1:0]  data_out_wire;

    //Instance creation:
    generate
        for (genvar i = 0; i < NUM_MODULES; i++) begin : GEN_MODULE
            t_hamming_tx #(
               .DATA_WIDTH       (PARTY_BIT),
               .PARITY_BIT       (PARITY_BIT),
               .ENCODED_DATA     (ENCODED_DATA)
            ) t_hamming_tx_i (
               .data_in           (data_in[i*PARTY_BIT +: PARTY_BIT]),
               .data_out          (data_out_wire[i*ENCODED_DATA +: ENCODED_DATA])
            );
        end
    endgenerate

    assign data_out = data_out_wire;

endmodule



module t_hamming_tx #(
    parameter DATA_WIDTH       = 4,
    parameter PARITY_BIT       = 3,
    parameter ENCODED_DATA     = PARITY_BIT + DATA_WIDTH + 1
)(
    input  [DATA_WIDTH-1:0]       data_in,
    output  reg[ENCODED_DATA-1:0] data_out
);

    reg [PARITY_BIT-1:0] parity;
    integer i, j, count;
    reg [ENCODED_DATA_BIT:0] pos;

    always @(*) begin
        data_out = {ENCODED_DATA{1'b0}};
        parity   = {PARITY_BIT{1'b0}};
        count    = 0;

        for (pos = 1; pos < ENCODED_DATA; pos = pos + 1) begin
            if (count < DATA_WIDTH) begin
                if ((pos & (pos - 1))!= 0) begin
                    data_out[pos] = data_in[count];
                    count = count + 1;
                end
            end
        end

        for (j = 0; j < PARITY_BIT; j = j + 1) begin
            for (i = 1; i <= ENCODED_DATA-1; i = i + 1) begin
                if ((i & (1 << j))!= 0) begin
                    parity[j] = parity[j] ^ data_out[i];
                end
            end
        end

        for (j = 0; j < PARITY_BIT; j = j + 1) begin
            data_out[(1 << j)] = parity[j]. 
        end
    end

endmodule

input.rtl/hebb_gates.sv:
module hebb_gates(
   input  logic               clk,
   input  logic               rst,
   input  logic               start, // To start the FSM
   input  logic  signed [3:0] a, // First Input
   input  logic  signed [3:0] b, // Second Input
   input  logic         [1:0] gate_select, // To provide the targets for a selected gate in order to train
   output logic  signed [3:0] w1, // Weight 1 obtained by training
   output logic  signed [3:0] w2, // Weight 2 obtained by training
   output logic  signed [3:0] bias,// Bias obtained by training
   output logic [3:0] present_state,// Present State of the Training FSM
   output logic [3:0] next_state // Next_State of the Training FSM

);
   logic signed [3:0] t1;
   logic signed [3:0] t2;
   logic signed [3:0] t3;
   logic signed [3:0] t4;

   gate_target dut(
       .gate_select(gate_select),
       .o_1        (t1),
       .o_2        (t2),
       .o_3        (t3),
       .o_4        (t4)
   );

   localparam [3:0] S0 = 4'd0;
   localparam [3:0] S1 = 4'd1;
   localparam [3:0] S2 = 4'd2;
   localparam [3:0] S3 = 4'd3;
   localparam [3:0] S4 = 4'd4;
   localparam [3:0] S5 = 4'd5;
   localparam [3:0] S6 = 4'd6;
   localparam [3:0] S7 = 4'd7;
   localparam [3:0] S8 = 4'd8;
   localparam [3:0] S9 = 4'd9;
   localparam [3:0] S10 = 4'd10;

   logic [2:0] iteration;
   logic signed [3:0] x1;
   logic signed [3:0] x2;
   logic signed [3:0] delta_w1;
   logic signed [3:0] delta_w2;
   logic signed [3:0] delta_b;
   logic signed [3:0] w1_reg;
   logic signed [3:0] w2_reg;
   logic signed [3:0] bias_reg;
   logic signed [1:0] target;
   logic delta_en;
   logic sum_en;
   logic clr_en;
   logic cap_en;

   always_comb begin
     if(cap_en ) begin
        x1 = a;
        x2 = b;
     end else begin
        x1 = x1 + 4'h0;
        x2 = x2 + 4'h0;
     end

   end

   always_comb begin

     if(delta_en) begin
       delta_w1 = x1 * target;
       delta_w2 = x2 * target;
       delta_b  = target;
     end else begin
       delta_w1 = delta_w1 + 4'h0;
       delta_w2 = delta_w2 + 4'h0;
       delta_b  = delta_b + 4'h0; 
   end

  end

  always_comb begin

     if(sum_en) begin
       w1_reg = w1_reg + delta_w1;
       w2_reg = w2_reg + delta_w2;
       bias_reg = bias_reg + delta_b;
     end else begin
       w1_reg = w1_reg + 4'h0;
       w2_reg = w2_reg + 4'h0;
       bias_reg = bias_reg + 4'h0;
   end
  end

   always_comb begin

     if(clr_en) begin
       w1_reg = 0;
       w2_reg = 0;
       bias_reg = 0;
     end else begin
       w1_reg = w1_reg + 4'h0;
       w2_reg = w2_reg + 4'h0;
       bias_reg = bias_reg + 4'h0; 
    end
   end

   always_ff@(posedge clk or negedge rst) begin
       if(!rst) begin
          present_state <= S0;
          iteration <= 0;
        end else
          present_state <= next_state;
   end

   always_comb begin
        next_state = present_state;

     case(present_state)
             S0  : begin 
                      if(start)
                         next_state = S1;
                      else
                         next_state = S0;
                   end
             S1  : begin 
                         next_state = S2;
                   end
             S2  : begin 
                      if(iteration == 0)
                        next_state = S3;
                     else if(iteration == 1)
                        next_state = S4;
                     else if(iteration == 2)
                        next_state = S5;
                     else 
                        next_state = S6;
                   end
             S3  : begin 
                         next_state = S7;

                   end
             S4  : begin 
                         next_state = S7;
                  end
             S5  : begin 
                         next_state = S7;
                  end
             S6  : begin 
                         next_state = S7;
                  end
             S7  :begin
                         next_state = S8;
                  end
             S8  : begin
                         next_state = S9;
                  end
             S9  : begin
                      if(iteration < 4)
                         next_state = S1;
                      else
                         next_state = S10;
                   end
             S10 : begin
                      next_state = S0;
                   end
             default : ;
     endcase
   end 

   always_comb begin

      case(present_state)
             S0 : begin
                    clr_en = 1;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en   = 0;
                    iteration = 0;
                    target = target + 4'h0;
                  end 
             S1 : begin
                    clr_en = 0;
                    cap_en = 1;
                    delta_en = 0;
                    sum_en = 0;  
                    iteration = iteration + 0;  
                    target = target + 4'h0;              
                  end
             S2 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0; 
                    iteration = iteration + 0;     
                    target = target + 4'h0;              
                  end
             S3 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t1;
                  end
             S4 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t2;
                  end     

             S5 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t3;
                  end  
             S6 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t4;
                  end        
             S7 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 1;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = target + 4'h0;
                  end
             S8 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 1;
                    iteration = iteration + 1;
                    target = target + 4'h0;
                  end
             S9 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = target + 4'h0;
                  end  
             S10 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = target + 4'h0;
                  end



           default : begin
                      clr_en = 0;
                      cap_en = 0;
                      delta_en = 0;
                      sum_en = 0;
                      iteration = 0;
                      target = target + 4'h0;
                     end
       endcase
   end
   assign w1 = w1_reg;
   assign w2 = w2_reg;
   assign bias = bias_reg;

endmodule

module gate_target(
   input  logic        [1:0] gate_select,
   output logic signed [3:0] o_1,
   output logic signed [3:0] o_2,
   output logic signed [3:0] o_3,
   output logic signed [3:0] o_4
);
   always_comb begin
     case(gate_select)
          2'b00 : begin 
                    o_1 =  1; 
                    o_2 = -1; 
                    o_3 = -1; 
                    o_4 = -1; 
                  end
          2'b01 : begin 
                    o_1 =  1; 
                    o_2 =  1; 
                    o_3 =  1; 
                    o_4 = -1; 
                  end
          2'b10 : begin 
                    o_1 =  1; 
                    o_2 =  1; 
                    o_3 =  1; 
                    o_4 = -1; 
                  end
          2'b11 : begin 
                    o_1 =  1; 
                    o_2 = -1; 
                    o_3 = -1; 
                    o_4 = -1; 
                  end
        default : begin
                    o_1 =  0; 
                    o_2 =  0; 
                    o_3 =  0; 
                    o_4 =  0; 
                  end
        endcase
   end
endmodule

