                    cap_en = 0;
                    delta_en = 1;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = target + 4'h0;
                  end
             S8 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 1;
                    iteration = iteration + 1;
                    target = target + 4'h0;
                  end
             S9 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = target + 4'h0;
                  end  
             S10 : begin
