module moving_average(
    input wire clk,
    input wire reset,
    input wire [11:0] data_in,
    output reg [11:0] data_out
);

reg [11:0] sum;
integer count = 0;

always @(posedge clk) begin
    if (reset) begin
        sum <= 0;
        count <= 0;
    end else begin
        sum <= {sum[10:0], data_in}; // shift left by 1 bit
        count <= count + 1;

        if (count == 8) begin
            data_out <= sum / 8; // divide the sum by 8
            count <= 0;
        end
    end
end

endmodule

input.rtl/moving_average.v:
module moving_average(
    input wire clk,
    input wire reset,
    input  wire [11 : 0] data_in,
    output wire [11 : 0] data_out
);

reg [11 : 0] memory [7 : 0];
reg [14 : 0] sum;
reg [2  : 0] write_address;
wire [2 : 0] next_address;
reg [11 : 0] read_data;

assign next_address=write_address + 1'b1;
assign data_out=sum[14 : 3];

    // write current input to memory
    integer i;
    always @(posedge clk ) begin
        if (reset == 1'b1) begin
            for (i = 0 ;i < 8 ; i = i + 1 ) begin
                memory[i]<='h0;
            end
        end else begin
            memory[write_address]<=data_in;
        end
    end

    // read the oldest element written to memory
    always @(posedge clk ) begin
        if(reset == 1'b1)begin
            read_data<='h0;
        end else begin
            read_data<=memory[next_address];
        end
    end

    // increase the write address to move onto the next data
    always @(posedge clk ) begin
        if(reset == 1'b1)begin
            write_address<='h0;
        end else begin
            write_address<=write_address + 1'b1;
        end
    end

    // calculate sum by adding the latest data to the sum and substracting the oldest data
    always @(posedge clk ) begin
        if(reset == 1'b1)begin
            sum<='h0;
        end else begin
            sum<=sum+data_in-read_data;
        end
    end

endmodule

output.rtl/moving_average.v:
module moving_average_enhanced(
    input wire clk,
    input wire reset,
    input  wire enable,
    input  wire [11 : 0] data_in,
    output wire [11 : 0] data_out
);

reg [11 : 0] memory [7 : 0];
reg [14 : 0] sum;
reg [2  : 0] write_address;
wire [2 : 0] next_address;
reg [11 : 0] read_data;

// Additional logic to handle enabling and disabling of the module
always @(posedge clk) begin
    if (reset == 1'b1) begin
        for (int i = 0; i < 8; i = i + 1) begin
            memory[i] <= 'h0;
        end
    end else if (enable == 1'b1) begin
        memory[write_address] <= data_in;
    end
end

// Additional logic to handle reading data when enabled
always @(posedge clk) begin
    if (reset == 1'b1) begin
        read_data <= 'h0;
    end else if (enable == 1'b1) begin
        read_data <= memory[next_address];
    end
end

// Additional logic to handle writing address when enabled
always @(posedge clk) begin
    if (reset == 1'b1) begin
        write_address <= 'h0;
    end else if (enable == 1'b1) begin
        write_address <= write_address + 1'b1;
    end
end

// Additional logic to handle sum calculation when enabled
always @(posedge clk) begin
    if (reset == 1'b1) begin
        sum <= 'h0;
    end else if (enable == 1'b1) begin
        sum <= sum + data_in - read_data;
    end
end

// Output logic to calculate the moving average based on the sum and the number of samples
assign data_out = (enable == 1'b1)? (sum >> 3) : 'h0;

endmodule

output.rtl/nbit_swizzling.sv:
module nbit_swizzling #(parameter DATA_WIDTH = 64) (
  input wire [DATA_WIDTH-1:0] data_in,
  input wire [1:0] sel,
  output reg [DATA_WIDTH-1:0] data_out
);

  // Bitwise operations to reverse the data based on the selection signal
  always @(*) begin
    if (sel == 2'b00) begin
      // Reverse the entire input
      data_out = ~data_in;
    end else if (sel == 2'b01) begin
      // Reverse the first half of the input
      data_out = {data_in[DATA_WIDTH-2:0], data_in[DATA_WIDTH-1:1]};
    end else if (sel == 2'b10) begin
      // Reverse the second half of the input
      data_out = {data_in[DATA_WIDTH-4:2], data_in[DATA_WIDTH-1:4]};
    end else if (sel == 2'b11) begin
      // Reverse all sections of the input
      data_out = {data_in[DATA_WIDTH-8:4], data_in[DATA_WIDTH-7:5], data_in[DATA_WIDTH-6:6], data_in[DATA_WIDTH-5:7], data_in[DATA_WIDTH-4:8], data_in[DATA_WIDTH-3:10], data_in[DATA_WIDTH-2:12], data_in[DATA_WIDTH-1:14]};
    end else begin
      // Default case: do not modify the input
      data_out = data_in;
    end
  end

endmodule

