output.rtl/neuromorphic_array.sv:
module neuromorphic_array #(
    parameter NEURONS = 8,       // Number of neurons
    parameter INPUTS = 8,        // Number of inputs
    parameter OUTPUTS = 8         // Number of outputs
) (
    input  logic [7:0] ui_in,       // Control input
    input logic [7:0] uio_in,      // Input data
    output logic [7:0] uo_out,     // Output data
    input logic clk,                // Clock
    input logic rst_n               // Reset
);
    // Internal wires for neuron outputs
    logic [7:0] neuron_outputs [0:NEURONS-1];

    // Instantiate the neurons
    genvar i;
    generate
        for (i=0; i<NEURONS; i++) begin : neuron
            single_neuron_dut dut (
               .clk(clk),
               .rst_n(rst_n),
               .control(ui_in[0]),
               .seq_in(uio_in),
               .seq_out(neuron_outputs[i])
            );
        end
    endgenerate

    // Combine outputs from the last neuron
    assign uo_out = neuron_outputs[NEURONS-1]; // Output from the last neuron

endmodule

module single_neuron_dut (
    input logic clk,
    input logic rst_n,
    input logic control,        // Control signal
    input logic [7:0] seq_in,   // Input sequence
    output logic [7:0] seq_out   // Output sequence
);
    // Insert local variables and logic here 
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            seq_out <= 8'd0;
        end else if (control) begin
            seq_out <= seq_in;
        end
    end
endmodule

input.rtl/one_hot_gen.sv:
module one_hot_gen #(
    parameter NS_A = 'd8,
    parameter NS_B = 'd4
) (
    input  logic                 clk,
    input  logic                 rst_async_n,
    input  logic [1:0]           i_config,
    input  logic                 i_start,
    input  logic                 o_ready,
    output logic [NS_A+NS_B-1:0] o_address_one_hot
);

typedef enum logic [2:0] {IDLE = 2'b00, REGION_A = 2'b01, REGION_B = 2'b10} state_t;

// ----------------------------------------
// - Wires/Registers creation
// ----------------------------------------
state_t state_ff, state_nx;
logic [NS_A-1:0] region_A_ff, region_A_nx;
logic [NS_B-1:0] region_B_ff, region_B_nx;
logic A_to_B, B_to_A, only_A, only_B;

// Input register
logic [2:0] config_ff;

// ----------------------------------------
// - Wire connections
// ----------------------------------------

// Region change flags
assign A_to_B = ( config_ff[1] & ~config_ff[0]);
assign B_to_A = ( config_ff[1] &  config_ff[0]);
assign only_A = (~config_ff[0] & ~config_ff[0]);
assign only_B = (~config_ff[0] &  config_ff[0]);

// Output assignment (Region A concatenated with Region B)
assign o_address_one_hot = {region_A_ff, region_B_ff};

// ----------------------------------------
// - Registers
// ----------------------------------------

always_ff @(posedge clk or negedge rst_async_n) begin : input_register
    if(~rst_async_n) begin
        config_ff <= 0;
    end else begin
        if(i_start && state_ff == IDLE) begin
            config_ff <= i_config;
        end
    end
end

always_ff @(posedge clk or negedge rst_async_n) begin : reset_regs
    if(~rst_async_n) begin
        o_ready <= 1;
        state_ff <= IDLE;
        region_A_ff <= {NS_A{1'b0}};
        region_B_ff <= {NS_B{1'b0}};
    end else begin
        o_ready <= (state_nx == IDLE);
        state_ff <= state_nx;
        region_A_ff <= region_A_nx;
        region_B_ff <= region_B_nx;
    end
end

// ----------------------------------------
// - One-hot address generation
// ----------------------------------------

always_comb begin : drive_regions
    case(state_ff)
        IDLE: begin
            if(i_start) begin
                region_A_nx[NS_A] = (~i_config[0]);
                region_B_nx[NS_B] = (i_config[0]);
            end else begin
                region_A_nx[NS_A] = 1'b0;
                region_B_nx[NS_B] = 1'b0;
            end

            region_A_nx[NS_A-2:0] = {(NS_A-1){1'b0}};
            region_B_nx[NS_B-2:0] = {(NS_B-1){1'b0}};
        end
        REGION_A: begin
            region_A_nx = region_A_ff >> 1;

            if(region_A_ff[0]) begin
                region_B_nx[NS_B] = A_to_B;
            end else begin
                region_B_nx[NS_B] = 1'b0;
            end
            region_B_nx[NS_B-2:0] = {(NS_B-1){1'b0}};
        end
        REGION_B: begin
            if(region_B_ff[0]) begin
                region_A_nx[NS_A] = B_to_A;
            end else begin
                region_A_nx[NS_A] = 1'b0;
            end
            region_A_nx[NS_A-2:0] = {(NS_A-1){1'b0}};

            region_B_nx = region_B_ff >> 1;
        end
        default: begin
            region_A_nx = {NS_A{1'b0}};
            region_B_nx = {NS_B{1'b0}};
        end
    endcase
end

// ----------------------------------------
// - FSM update
// ----------------------------------------

always_comb begin : update_state
    case(state_ff)
        IDLE: begin
            if(i_start) begin
                if(i_config[0]) begin
                    state_nx = REGION_B;
                end else begin
                    state_nx = REGION_A;
                end
            end else begin
                state_nx = IDLE;
            end
        end
        REGION_A: begin
            if(region_A_ff[0]) begin
                if(A_to_B) begin
                    state_nx = REGION_B;
                end else begin
                    state_nx = IDLE;
                end
            end else begin
                state_nx = REGION_A;
            end
        end
        REGION_B: begin
            if(region_B_ff[0]) begin
                if(B_to_A) begin
                    state_nx = REGION_A;
                end else begin
                    state_nx = IDLE;
                end
            end else begin
                state_nx = REGION_B;
            end
        end
        default: begin
            state_nx = IDLE;
        end
    endcase
end

endmodule : one_hot_gen

output.rtl/one_hot_gen.sv:
module one_hot_gen #(
    parameter NS_A = 'd8,
    parameter NS_B = 'd4
) (
    input  logic                 clk,
    input  logic                 rst_async_n,
    input  logic [1:0]           i_config,
    input  logic                 i_start,
    input  logic                 o_ready,
    output logic [NS_A+NS_B-1:0] o_address_one_hot
);

typedef enum logic [2:0] {IDLE = 2'b00, REGION_A = 2'b01, REGION_B = 2'b10} state_t;

// ----------------------------------------
// - Wires/Registers creation
// ----------------------------------------
state_t state_ff, state_nx;
logic [NS_A-1:0] region_A_ff, region_A_nx;
logic [NS_B-1:0] region_B_ff, region_B_nx;
logic A_to_B, B_to_A, only_A, only_B;

// Input register
logic [2:0] config_ff;

// ----------------------------------------
// - Wire connections
// ----------------------------------------

// Region change flags
assign A_to_B = ( config_ff[1] & ~config_ff[0]);
assign B_to_A = ( config_ff[1] &  config_ff[0]);
assign only_A = (~config_ff[0] & ~config_ff[0]);
assign only_B = (~config_ff[0] &  config_ff[0]);

// Output assignment (Region A concatenated with Region B)
assign o_address_one_hot = {region_A_ff, region_B_ff};

// ----------------------------------------
// - Registers
// ----------------------------------------

always_ff @(posedge clk or negedge rst_async_n) begin : input_register
    if(~rst_async_n) begin
        config_ff <= 0;
    end else begin
        if(i_start && state_ff == IDLE) begin
            config_ff <= i_config;
        end
    end
end

always_ff @(posedge clk or negedge rst_async_n) begin : reset_regs
    if(~rst_async_n) begin
        o_ready <= 1;
        state_ff <= IDLE;
        region_A_ff <= {NS_A{1'b0}};
        region_B_ff <= {NS_B{1'b0}};
    end else begin
        o_ready <= (state_nx == IDLE);
        state_ff <= state_nx;
        region_A_ff <= region_A_nx;
        region_B_ff <= region_B_nx;
    end
end

// ----------------------------------------
// - One-hot address generation
// ----------------------------------------

always_comb begin : drive_regions
    case(state_ff)
        IDLE: begin
            if(i_start) begin
                region_A_nx[NS_A] = (~i_config[0]);
                region_B_nx[NS_B] = (i_config[0]);
            end else begin
                region_A_nx[NS_A] = 1'b0;
                region_B_nx[NS_B] = 1'b0;
            end

            region_A_nx[NS_A-2:0] = {(NS_A-1){1'b0}};
            region_B_nx[NS_B-2:0] = {(NS_B-1){1'b0}};
        end
        REGION_A: begin
            region_A_nx = region_A_ff >> 1;

            if(region_A_ff[0]) begin
                region_B_nx[NS_B] = A_to_B;
            end else begin
                region_B_nx[NS_B] = 1'b0;
            end
            region_B_nx[NS_B-2:0] = {(NS_B-1){1'b0}};
        end
        REGION_B: begin
            if(region_B_ff[0]) begin
                region_A_nx[NS_A] = B_to_A;
            end else begin
                region_A_nx[NS_A] = 1'b0;
            end
            region_A_nx[NS_A-2:0] = {(NS_A-1){1'b0}};

            region_B_nx = region_B_ff >> 1;
        end
        default: begin
            region_A_nx = {NS_A{1'b0}};
            region_B_nx = {NS_B{1'b0}};
        end
    endcase
end

// ----------------------------------------
// - FSM update
// ----------------------------------------

always_comb begin : update_state
    case(state_ff)
        IDLE: begin
            if(i_start) begin
                if(i_config[0]) begin
                    state_nx = REGION_B;
                end else begin
                    state_nx = REGION_A;
                end
            end else begin
                state_nx = IDLE;
            end
        end
        REGION_A: begin
            if(region_A_ff[0]) begin
                if(A_to_B) begin
                    state_nx = REGION_B;
                end else begin
                    state_nx = IDLE;
                end
            end else begin
                state_nx = REGION_A;
            end
        end
        REGION_B: begin
            if(region_B_ff[0]) begin
                if(B_to_A) begin
                    state_nx = REGION_A;
                end else begin
                    state_nx = IDLE;
                end
            end else begin
                state_nx = REGION_B;
            end
        end
        default: begin
            state_nx = IDLE;
        end
    endcase
end

endmodule : one_hot_gen

output.rtl/packet_controller.sv:
module packet_controller(
    input logic clk,
    input logic rst,
    input logic rx_valid_i,
    input logic [7:0] rx_data_8_i,
    input logic tx_done_tick_i,
    output logic tx_start_o,
    output logic [7:0] tx_data_8_o
);

    // Define states
    typedef enum {
        S_IDLE,
        S_GOT_8_BYTES,
        S_RECV_CHECKSUM,
        S_BUILD_RESPONSE,
        S_SEND_FIRST_BYTE,
        S_RESPONSE_READY
    } state_t;

    // Declare internal signals
    logic [15:0] header;
    logic [15:0] payload;
    logic [7:0] opcode;
    logic [7:0] checksum;
    state_t state;

    always_ff @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= S_IDLE;
            // Initialize internal signals
            header <= 16'd0;
            payload <= 16'd0;
            opcode <= 8'd0;
            checksum <= 8'd0;
        end else begin
            case (state)
                S_IDLE: begin
                    if (rx_valid_i && rx_data_8_i == 16'hBACD) begin
                        state <= S_GOT_8_BYTES;
                        // Load header into internal signals
                        header <= {rx_data_8_i[15:8], rx_data_8_i[7:0]};
                    end
                end
                S_GOT_8_BYTES: begin
                    // Accumulate payload bytes
                    payload <= {payload[15:8], rx_data_8_i};
                    // Calculate checksum
                    checksum <= $unsigned(checksum) + rx_data_8_i;
                    // Check for complete packet
                    if (payload == 16'd0) begin
                        state <= S_RECV_CHECKSUM;
                        // Extract opcode from header
                        opcode <= header[7:0];
                    end
                end
                S_RECV_CHECKSUM: begin
                    // Compute checksum and check against header
                    if ($unsigned(checksum)!= header[15:8]) begin
                        state <= S_IDLE;
                    end else begin
                        state <= S_BUILD_RESPONSE;
                    end
                end
                S_BUILD_RESPONSE: begin
                    // Compute result based on opcode
                    payload <= opcode == 8'd0? payload + payload : payload - payload;
                    // Update state for next iteration
                    state <= S_SEND_FIRST_BYTE;
                end
                S_SEND_FIRST_BYTE: begin
                    // Send first byte of response
                    tx_start_o <= 1'b1;
                    tx_data_8_o <= payload[7:0];
                    state <= S_RESPONSE_READY;
                end
                S_RESPONSE_READY: begin
                    // Continue transmission of remaining bytes
                    if (tx_done_tick_i) begin
                        state <= S_IDLE;
                    end
                end
            endcase
        end
    end

endmodule

output.rtl/palindrome_detect.sv:
module palindrome_detect #( 
parameter N=3
) (
input clk,
input reset,
input bit_stream,
output palindrome_detected
);

reg [N-1:0] reg_window;
reg [2*N-1:0] window;
reg [N-1:0] reverse_window;
reg [N-1:0] xor_result;
reg [N-1:0] max_value;
wire [N-1:0] compare_result;

always @(posedge clk) begin
  if(reset) begin
    reg_window <= '0;
    window <= '0;
    reverse_window <= '0;
    xor_result <= '0;
    max_value <= '0;
  end else begin
    reg_window <= {reg_window[N-1:0], bit_stream};
    window <= {reg_window[2*N-1:N], reg_window[N-1:0]};
    reverse_window <= {reg_window[N-1:0], reg_window[2*N-1:N]};
    xor_result <= reg_window ^ window;
    max_value <= {xor_result[N-1:0], reverse_window[N-1:0]};
    palindrome_detected <= (max_value == window);
  end
end

endmodule

output.rtl/password_generator.sv:
module password_generator #(
    parameter WIDTH = 4  
) (
    input logic clk,
    input logic reset,
    output logic [(WIDTH*8)-1:0] password 
);

  logic [7:0] char_array[WIDTH-1:0];  
  logic [7:0] counter;  
  logic [1:0] char_type; 

  int i;

  // Insert code here for Counter Logic for pseudo-random generation
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      counter <= 0;
      for (i=0; i<WIDTH; i++) begin
        char_array[i] <= 0;
      end
    end else begin
      counter <= counter + 1;
    end
  end

  // Insert code here for Generate password characters
  always @(*) begin
    case (char_type)
      2'b00: begin
        password <= ((counter + char_array[(i+1)%WIDTH]) % 26) + 8'd97;
      end
      2'b01: begin
        password <= ((counter + i) % 26) + 8'd65;
      end
      2'b10: begin
        password <= ((counter + char_array[(i+WIDTH-1)%WIDTH]) % 14) + 8'd33;
      end
      2'b11: begin
        password <= ((counter + i) % 10) + 8'd48;
      end
      default: begin
        password <= 8'bX;
      end
    endcase
  end

endmodule

input.rtl/perceptron_gates.sv:
module perceptron_gates (
   input  logic clk,// Posedge clock
   input  logic rst_n,// Negedge reset
   input  logic signed [3:0] x1, // First Input of the Perceptron
   input  logic signed [3:0] x2, // Second Input of the Perceptron
   input  logic learning_rate, // Learning rate (alpha)
   input  logic signed [3:0] threshold, // Threshold value
   input  logic [1:0] gate_select, // Gate selection for target values
   output logic signed [3:0] percep_w1, // Trained Weight 1 
   output logic signed [3:0] percep_w2, // Trained Weight 2
   output logic signed [3:0] percep_bias, // Trained Bias
   output logic [3:0] present_addr, // Current address in microcode ROM
   output logic stop, // Condition to indicate no learning has occurred(i.e. no weight change between iterations)
   output logic [2:0] input_index,// Vector to track the selection of target for a given input combination for a gate
   output logic signed [3:0] y_in, // Calculated Response
   output logic signed [3:0] y, // Calculated Response obtained by comparing y_in against a threshold value
   output logic signed [3:0] prev_percep_wt_1,//Value of Weight 1 during a previous iteration
   output logic signed [3:0] prev_percep_wt_2,//Value of Weight 2 during a previous iteration
   output logic signed [3:0] prev_percep_bias // Value of Bias during a previous iteration
);

   logic [15:0] microcode_rom [0:5];
   logic [3:0]  next_addr;
   logic [3:0]  train_action;
   logic [3:0]  microcode_addr;
   logic [15:0] microinstruction;
   logic signed [3:0] t1, t2, t3, t4;

   gate_target dut (
       .gate_select(gate_select),
       .o_1(t1),
       .o_2(t2),
       .o_3(t3),
       .o_4(t4)
   );

   logic signed [3:0] percep_wt_1_reg;
   logic signed [3:0] percep_wt_2_reg;
   logic signed [3:0] percep_bias_reg;


   logic signed [3:0] target;
   logic signed [3:0] prev_wt1_update;
   logic signed [3:0] prev_wt2_update;
   logic signed [3:0] prev_bias_update;

   logic signed [3:0] wt1_update;
   logic signed [3:0] wt2_update;
   logic signed [3:0] bias_update;
   logic [7:0] epoch_counter;

   assign  prev_percep_wt_1 = prev_wt1_update;
   assign  prev_percep_wt_2 = prev_wt2_update;
   assign  prev_percep_bias = prev_bias_update;

   initial begin 
      microcode_rom[0] = 16'b0001_0000_0000_0000; 
      microcode_rom[1] = 16'b0010_0001_0000_0000; 
      microcode_rom[2] = 16'b0011_0010_0000_0000; 
      microcode_rom[3] = 16'b0100_0011_0000_0000; 
      microcode_rom[4] = 16'b0101_0100_0000_0000; 
      microcode_rom[5] = 16'b0000_0101_0000_0000; 
   end  

   always@(*) begin
      microinstruction = microcode_rom[microcode_addr];
      next_addr        = microinstruction[15:12];
      train_action     = microinstruction[11:8];
   end

   always_ff @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         present_addr    <= 4'd0;
         microcode_addr  <= 4'd0;
         percep_wt_1_reg <= 4'd0;
         percep_wt_2_reg <= 4'd0;
         percep_bias_reg <= 4'd0;
         input_index     <= 2'd0;
         stop            <= 1'b0;
      end else begin
         present_addr    <= next_addr;
         microcode_addr  <= present_addr;
      end
   end

   always_comb begin
      case (train_action)
         4'd0:  begin 
                   percep_wt_1_reg = 4'd0;
                   percep_wt_2_reg = 4'd0;
                   percep_bias_reg = 4'd0;
                   stop = 1'b0;
                   next_addr = next_addr + 4'd0;
                   y_in = 4'd0;
                   y    = 4'd0;
                   prev_wt1_update = 4'd0;
                   prev_wt2_update = 4'd0;
                   prev_bias_update = 4'd0;
                   input_index = 0;
                   target = 0;
                   wt1_update = 0;
                   wt2_update = 0;
                   bias_update = 0;
                   epoch_counter = 0;
                end
         4'd1 : begin 
                   y_in = percep_bias_reg + (x1 * percep_wt_1_reg) + (x2 * percep_wt_2_reg); 
                   if (y_in > threshold)
                      y = 4'd1;
                   else if (y_in >= -threshold && y_in <= threshold)
                      y = 4'd0;
                   else
                      y = -4'd1;

                   percep_wt_1_reg  = percep_wt_1_reg  + 4'd0;
                   percep_wt_2_reg  = percep_wt_2_reg  + 4'd0;
                   percep_bias_reg  = percep_bias_reg  + 4'd0;
                   prev_wt1_update  = prev_wt1_update  + 4'd0;
                   prev_wt2_update  = prev_wt2_update  + 4'd0;
                   prev_bias_update = prev_bias_update + 4'd0;
                   input_index = input_index + 0;
                   next_addr = next_addr + 4'd0;
                   stop = stop + 1'b0;
                   target = target + 4'd0;
                   wt1_update = wt1_update + 4'd0 ;
                   wt2_update = wt2_update + 4'd0 ;
                   bias_update = bias_update + 4'd0 ;
                   epoch_counter = epoch_counter + 0;
                end
         4'd2 : begin
                   if(input_index == 0)
                        target = t1;
                   else if(input_index == 1)
                        target = t2;
                   else if(input_index == 2)
                        target = t3;
                   else if(input_index == 3)
                        target = t4;
                   else begin
                        input_index = 0;
                        target = 0;
                   end
                   stop = stop + 1'b0;
                   input_index = input_index + 0;
                   next_addr = next_addr + 4'd0;
                   target = target + 4'd0;
                   prev_wt1_update  = prev_wt1_update  + 4'd0;
                   prev_wt2_update  = prev_wt2_update  + 4'd0;
                   prev_bias_update = prev_bias_update + 4'd0;

                   percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                   percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                   percep_bias_reg = percep_bias_reg + 4'd0;
                   y_in = y_in + 4'd0;
                   y = y + 4'd0;
                   wt1_update = wt1_update + 4'd0 ;
                   wt2_update = wt2_update + 4'd0 ;
                   bias_update = bias_update + 4'd0 ;
                   epoch_counter = epoch_counter + 0;
                end
         4'd3 : begin
                   if (y != target) begin
                        wt1_update = learning_rate * x1 * target ;
                        wt2_update = learning_rate * x2 * target ;
                        bias_update = learning_rate * target ; 
                    end else begin
                        wt1_update = 0 ;
                        wt2_update = 0 ;
                        bias_update = 0 ;     
                    end    
                    percep_wt_1_reg = percep_wt_1_reg + wt1_update;
                    percep_wt_2_reg = percep_wt_2_reg + wt2_update;
                    percep_bias_reg = percep_bias_reg + bias_update;
                    prev_wt1_update  = prev_wt1_update  + 4'd0;
                    prev_wt2_update  = prev_wt2_update  + 4'd0;
                    prev_bias_update = prev_bias_update + 4'd0;
                    y_in = y_in + 4'd0;
                    y = y + 4'd0;
                    stop = stop + 1'b0;
                    input_index = input_index + 0;
                    next_addr = next_addr + 4'd0;
                    target = target + 4'd0;
                    epoch_counter = epoch_counter + 0;
                end
         4'd4 : begin
                  if ((prev_wt1_update == wt1_update) & (prev_wt2_update == wt2_update) & (input_index == 4'd3)) begin 
                          epoch_counter = 0;
                          stop = 1'b1; 
                          input_index = 0;
                          next_addr = 4'd0;
                          percep_wt_1_reg = 0;
                          percep_wt_2_reg = 0;
                          percep_bias_reg = 0;
                          prev_wt1_update =  0;
                          prev_wt2_update =  0;
                          prev_bias_update = 0;
                          y_in = 0;
                          y = 0;
                          target = 0;
                          wt1_update = 0 ;
                          wt2_update = 0 ;
                          bias_update = 0 ;
                  end else begin
                          stop = 1'b0; 
                          input_index = input_index + 0;
                          epoch_counter = epoch_counter + 1;    
                          next_addr = 4'd5;    
                          percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                          percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                          percep_bias_reg = percep_bias_reg + 4'd0;
                          prev_wt1_update = prev_wt1_update + 4'd0;
                          prev_wt2_update = prev_wt2_update + 4'd0;
                          prev_bias_update = prev_bias_update + 4'd0;
                          y_in = y_in + 4'd0;
                          y = y + 4'd0;
                          target = target + 4'd0;
                          wt1_update = wt1_update + 4'd0 ;
                          wt2_update = wt2_update + 4'd0 ;
                          bias_update = bias_update + 4'd0 ;
                  end
                end
         4'd5 : begin
                          percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                          percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                          percep_bias_reg = percep_bias_reg + 4'd0;
                          prev_wt1_update  = wt1_update;
                          prev_wt2_update  = wt2_update;
                          prev_bias_update = bias_update;
                          next_addr = 4'd1;
                          input_index = input_index + 1;
                          stop = stop + 1'b0;
                          epoch_counter = epoch_counter + 0;
                          y_in = y_in + 4'd0;
                          y = y + 4'd0;
                          target = target + 4'd0;
                          wt1_update = wt1_update + 4'd0;
                          wt2_update = wt2_update + 4'd0;
                          bias_update = bias_update + 4'd0;
                end   
      default : begin
                          next_addr = next_addr + 4'd0;
                          percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                          percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                          percep_bias_reg = percep_bias_reg + 4'd0;
                          prev_wt1_update = prev_wt1_update + 4'd0;
                          prev_wt2_update = prev_wt2_update + 4'd0;
                          prev_bias_update = prev_bias_update + 4'd0;
                          stop = stop + 1'b0;
                          y_in = y_in + 4'd0;
                          y = y + 4'd0;
                          input_index = input_index + 0;
                          target = target + 4'd0;
                          wt1_update = wt1_update + 4'd0 ;
                          wt2_update = wt2_update + 4'd0 ;
                          bias_update = bias_update + 4'd0 ;
                          epoch_counter = epoch_counter + 0;
                end
      endcase
   end
   assign percep_w1 = percep_wt_1_reg;
   assign percep_w2 = percep_wt_2_reg;
   assign percep_bias = percep_bias_reg;

endmodule

module gate_target(
   input  logic        [1:0] gate_select,
   output logic signed [3:0] o_1,
   output logic signed [3:0] o_2,
   output logic signed [3:0] o_3,
   output logic signed [3:0] o_4
);
   always_comb begin
     case(gate_select)
          2'b00 : begin 
                    o_1 =  1; 
                    o_2 = -1; 
                    o_3 = -1; 
                    o_4 = -1; 
                  end
          2'b01 : begin 
                    o_1 =  1; 
                    o_2 =  1; 
                    o_3 =  1; 
                    o_4 = -1; 
                  end
          2'b10 : begin 
                    o_1 =  1; 
                    o_2 =  1; 
                    o_3 =  1; 
                    o_4 = -1; 
                  end
          2'b11 : begin 
                    o_1 =  1; 
                    o_2 = -1; 
                    o_3 = -1; 
                    o_4 = -1; 
                  end
        default : begin
                    o_1 =  0; 
                    o_2 =  0; 
                    o_3 =  0; 
                    o_4 =  0; 
                  end
        endcase
   end
endmodule

output.rtl/perceptron_gates.sv:
module perceptron_gates (
   input  logic clk,// Posedge clock
   input  logic rst_n,// Negedge reset
   input  logic signed [3:0] x1, // First Input of the Perceptron
   input  logic signed [3:0] x2, // Second Input of the Perceptron
   input  logic learning_rate, // Learning rate (alpha)
   input  logic signed [3:0] threshold, // Threshold value
   input  logic [1:0] gate_select, // Gate selection for target values
   output logic signed [3:0] percep_w1, // Trained Weight 1 
   output logic signed [3:0] percep_w2, // Trained Weight 2
   output logic signed [3:0] percep_bias, // Trained Bias
   output logic [3:0] present_addr, // Current address in microcode ROM
   output logic stop, // Condition to indicate no learning has occurred(i.e. no weight change between iterations)
   output logic [2:0] input_index,// Vector to track the selection of target for a given input combination for a gate
   output logic signed [3:0] y_in, // Calculated Response
   output logic signed [3:0] y, // Calculated Response obtained by comparing y_in against a threshold value
   output logic signed [3:0] prev_percep_wt_1,//Value of Weight 1 during a previous iteration
   output logic signed [3:0] prev_percep_wt_2,//Value of Weight 2 during a previous iteration
   output logic signed [3:0] prev_percep_bias // Value of Bias during a previous iteration
);

   logic [15:0] microcode_rom [0:5];
   logic [3:0]  next_addr;
   logic [3:0]  train_action;
   logic [3:0]  microcode_addr;
   logic [15:0] microinstruction;
   logic signed [3:0] t1, t2, t3, t4;

   gate_target dut (
       .gate_select(gate_select),
       .o_1(t1),
       .o_2(t2),
       .o_3(t3),
       .o_4(t4)
   );

   logic signed [3:0] percep_wt_1_reg;
   logic signed [3:0] percep_wt_2_reg;
   logic signed [3:0] percep_bias_reg;


   logic signed [3:0] target;
   logic signed [3:0] prev_wt1_update;
   logic signed [3:0] prev_wt2_update;
   logic signed [3:0] prev_bias_update;

   logic signed [3:0] wt1_update;
   logic signed [3:0] wt2_update;
   logic signed [3:0] bias_update;
   logic [7:0] epoch_counter;

   assign  prev_percep_wt_1 = prev_wt1_update;
   assign  prev_percep_wt_2 = prev_wt2_update;
   assign  prev_percep_bias = prev_bias_update;

   initial begin 
      microcode_rom[0] = 16'b0001_0000_0000_0000; 
      microcode_rom[1] = 16'b0010_0001_0000_0000; 
      microcode_rom[2] = 16'b0011_0010_0000_0000; 
      microcode_rom[3] = 16'b0100_0011_0000_0000; 
      microcode_rom[4] = 16'b0101_0100_0000_0000; 
      microcode_rom[5] = 16'b0000_0101_0000_0000; 
   end  

   always@(*) begin
      microinstruction = microcode_rom[microcode_addr];
      next_addr        = microinstruction[15:12];
      train_action     = microinstruction[11:8];
   end

   always_ff @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         present_addr    <= 4'd0;
         microcode_addr  <= 4'd0;
         percep_wt_1_reg <= 4'd0;
         percep_wt_2_reg <= 4'd0;
         percep_bias_reg <= 4'd0;
         input_index     <= 2'd0;
         stop            <= 1'b0;
      end else begin
         present_addr    <= next_addr;
         microcode_addr  <= present_addr;
      end
   end

   always_comb begin
      case (train_action)
         4'd0:  begin 
                   percep_wt_1_reg = 4'd0;
                   percep_wt_2_reg = 4'd0;
                   percep_bias_reg = 4'd0;
                   stop = 1'b0;
                   next_addr = next_addr + 4'd0;
                   y_in = 4'd0;
                   y    = 4'd0;
                   prev_wt1_update = 4'd0;
                   prev_wt2_update = 4'd0;
                   prev_bias_update = 4'd0;
                   input_index = 0;
                   target = 0;
                   wt1_update = 0;
                   wt2_update = 0;
                   bias_update = 0;
                   epoch_counter = 0;
                end
         4'd1 : begin 
                   y_in = percep_bias_reg + (x1 * percep_wt_1_reg) + (x2 * percep_wt_2_reg); 
                   if (y_in > threshold)
                      y = 4'd1;
                   else if (y_in >= -threshold && y_in <= threshold)
                      y = 4'd0;
                   else
                      y = -4'd1;

                   percep_wt_1_reg  = percep_wt_1_reg  + 4'd0;
                   percep_wt_2_reg  = percep_wt_2_reg  + 4'd0;
                   percep_bias_reg  = percep_bias_reg  + 4'd0;
                   prev_wt1_update  = prev_wt1_update  + 4'd0;
                   prev_wt2_update  = prev_wt2_update  + 4'd0;
                   prev_bias_update = prev_bias_update + 4'd0;
                   input_index = input_index + 0;
                   next_addr = next_addr + 4'd0;
                   stop = stop + 1'b0;
                   target = target + 4'd0;
                   wt1_update = wt1_update + 4'd0 ;
                   wt2_update = wt2_update + 4'd0 ;
                   bias_update = bias_update + 4'd0 ;
                   epoch_counter = epoch_counter + 0;
                end
         4'd2 : begin
                   if(input_index == 0)
                        target = t1;
                   else if(input_index == 1)
                        target = t2;
                   else if(input_index == 2)
                        target = t3;
                   else if(input_index == 3)
                        target = t4;
                   else begin
                        input_index = 0;
                        target = 0;
                   end
                   stop = stop + 1'b0;
                   input_index = input_index + 0;
                   next_addr = next_addr + 4'd0;
                   target = target + 4'd0;
                   prev_wt1_update  = prev_wt1_update  + 4'd0;
                   prev_wt2_update  = prev_wt2_update  + 4'd0;
                   prev_bias_update = prev_bias_update + 4'd0;

                   percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                   percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                   percep_bias_reg = percep_bias_reg + 4'd0;
                   y_in = y_in + 4'd0;
                   y = y + 4'd0;
                   wt1_update = wt1_update + 4'd0 ;
                   wt2_update = wt2_update + 4'd0 ;
                   bias_update = bias_update + 4'd0 ;
                   epoch_counter = epoch_counter + 0;
                end
         4'd3 : begin
                   if (y != target) begin
                        wt1_update = learning_rate * x1 * target ;
                        wt2_update = learning_rate * x2 * target ;
                        bias_update = learning_rate * target ; 
                    end else begin
                        wt1_update = 0 ;
                        wt2_update = 0 ;
                        bias_update = 0 ;     
                    end    
                    percep_wt_1_reg = percep_wt_1_reg + wt1_update;
                    percep_wt_2_reg = percep_wt_2_reg + wt2_update;
                    percep_bias_reg = percep_bias_reg + bias_update;
                    prev_wt1_update  = prev_wt1_update  + 4'd0;
                    prev_wt2_update  = prev_wt2_update  + 4'd0;
                    prev_bias_update = prev_bias_update + 4'd0;
                    y_in = y_in + 4'd0;
                    y = y + 4'd0;
                    stop = stop + 1'b0;
                    input_index = input_index + 0;
                    next_addr = next_addr + 4'd0;
                    target = target + 4'd0;
                    epoch_counter = epoch_counter + 0;
                end
         4'd4 : begin
                  if ((prev_wt1_update == wt1_update) & (prev_wt2_update == wt2_update) & (input_index == 4'd3)) begin 
                          epoch_counter = 0;
                          stop = 1'b1; 
                          input_index = 0;
                          next_addr = 4'd0;
                          percep_wt_1_reg = 0;
                          percep_wt_2_reg = 0;
                          percep_bias_reg = 0;
                          prev_wt1_update =  0;
                          prev_wt2_update =  0;
                          prev_bias_update = 0;
                          y_in = 0;
                          y = 0;
                          target = 0;
                          wt1_update = 0 ;
                          wt2_update = 0 ;
                          bias_update = 0 ;
                  end else begin
                          stop = 1'b0; 
                          input_index = input_index + 0;
                          epoch_counter = epoch_counter + 1;    
                          next_addr = 4'd5;    
                          percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                          percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                          percep_bias_reg = percep_bias_reg + 4'd0;
                          prev_wt1_update = prev_wt1_update + 4'd0;
                          prev_wt2_update = prev_wt2_update + 4'd0;
                          prev_bias_update = prev_bias_update + 4'd0;
                          y_in = y_in + 4'd0;
                          y = y + 4'd0;
                          target = target + 4'd0;
                          wt1_update = wt1_update + 4'd0 ;
                          wt2_update = wt2_update + 4'd0 ;
                          bias_update = bias_update + 4'd0 ;
                  end
                end
         4'd5 : begin
                          percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                          percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                          percep_bias_reg = percep_bias_reg + 4'd0;
                          prev_wt1_update  = wt1_update;
                          prev_wt2_update  = wt2_update;
                          prev_bias_update = bias_update;
                          next_addr = 4'd1;
                          input_index = input_index + 1;
                          stop = stop + 1'b0;
                          epoch_counter = epoch_counter + 0;
                          y_in = y_in + 4'd0;
                          y = y + 4'd0;
                          target = target + 4'd0;
                          wt1_update = wt1_update + 4'd0;
                          wt2_update = wt2_update + 4'd0;
                          bias_update = bias_update + 4'd0;
                end   
      default : begin
                          next_addr = next_addr + 4'd0;
                          percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                          percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                          percep_bias_reg = percep_bias_reg + 4'd0;
                          prev_wt1_update = prev_wt1_update + 4'd0;
                          prev_wt2_update = prev_wt2_update + 4'd0;
                          prev_bias_update = prev_bias_update + 4'd0;
                          stop = stop + 1'b0;
                          y_in = y_in + 4'd0;
                          y = y + 4'd0;
                          input_index = input_index + 0;
                          target = target + 4'd0;
                          wt1_update = wt1_update + 4'd0 ;
                          wt2_update = wt2_update + 4'd0 ;
                          bias_update = bias_update + 4'd0 ;
                          epoch_counter = epoch_counter + 0;
                end
      endcase
   end
   assign percep_w1 = percep_wt_1_reg;
   assign percep_w2 = percep_wt_2_reg;
   assign percep_bias = percep_bias_reg;

endmodule

module gate_target(
   input  logic        [1:0] gate_select,
   output logic signed [3:0] o_1,
   output logic signed [3:0] o_2,
   output logic signed [3:0] o_3,
   output logic signed [3:0] o_4
);
   always_comb begin
     case(gate_select)
          2'b00 : begin 
                    o_1 =  1; 
                    o_2 = -1; 
                    o_3 = -1; 
                    o_4 = -1; 
                  end
          2'b01 : begin 
                    o_1 =  1; 
                    o_2 =  1; 
                    o_3 =  1; 
                    o_4 = -1; 
                  end
          2'b10 : begin 
                    o_1 =  1; 
                    o_2 =  1; 
                    o_3 =  1; 
                    o_4 = -1; 
                  end
          2'b11 : begin 
                    o_1 =  1; 
                    o_2 = -1; 
                    o_3 = -1; 
                    o_4 = -1; 
                  end
        default : begin
                    o_1 =  0; 
                    o_2 =  0; 
                    o_3 =  0; 
                    o_4 =  0; 
                  end
        endcase
   end
endmodule

