module round_robin_arbiter #(
    parameter N = 4
)(
    input  wire             clk,
    input  wire             rstn,
    input  wire [N-1:0]     req,   
    output reg  [N-1:0]     grant   
);

    reg [$clog2(N)-1:0] pointer;
    reg [$clog2(N)-1:0] pointer_next;
    reg found;
    reg [N-1:0] timeout_counter;

    integer i;
    always @(*) begin
        grant        = {N{1'b0}};
        timeout_counter = {N{1'b0}};
        pointer_next = pointer;

        if (req!= 0) begin
           found = 1'b0;
            for (i = 0; i < N; i = i + 1) begin
                if (!found && req[(pointer + i) % N] == 1'b1) begin
                    grant[(pointer + i) % N] = 1'b1;

                    // Elevate the channel's priority for fairness
                    if (priority_level[i] == 1) begin
                        timeout_counter[i] = TIMEOUT;
                    end

                    pointer_next = (pointer + i + 1) % N;
                    found        = 1'b1;                    
                end
            end
        end
    end

    always @(posedge clk or negedge rstn) begin
        if (!rstn) begin
            pointer <= 0;
        end else begin
            pointer <= pointer_next;
        end
    end

    always @(posedge clk or negedge rstn) begin
        if (!rstn) begin
            timeout_counter <= {N{1'b0}};
        end else begin
            for (i = 0; i < N; i = i + 1) begin
                if (timeout_counter[i] > 0) begin
                    timeout_counter[i] = timeout_counter[i] - 1;
                end
            end
        end
    end

endmodule

