always @ (posedge clk_sig)
begin
  if (clk_en_sig)
  begin
    if (~|load_data_gain)
    begin
      left_sig <= #1 ~left_sig;
    end
    else
    begin
      left_sig <= #1 ~l_er0[DATA_WIDTH+2-1];
    end

    if (~|read_data_gain)
    begin
      right_sig <= #1 ~right_sig;
    end
    else
    begin
      right_sig <= #1 ~r_er0[DATA_WIDTH+2-1];
    end
  end
end
