module pipelined_skid_buffer (
    input wire clock,
    input wire rst,

    input wire [3:0] data_i,
    input wire valid_i,
    output wire ready_o,
    output wire valid_o,
    output wire [3:0] data_o,
    input wire ready_i
    );

    // Define internal variables
    reg [3:0] data_reg;
    reg buffer;

    // Define module functionality
    always @(posedge clock) begin
        if (rst) begin
            // Reset logic
            data_reg <= 4'b0;
            buffer <= 1'b0;
        end else begin
            // Input data handling
            if (valid_i &&!buffer) begin
                // Store input data in the internal register
                data_reg <= data_i;
                buffer <= 1'b1;
            end else if (!valid_i && buffer) begin
                // Forward stored data to the output when ready
                data_o <= data_reg;
                valid_o <= 1'b1;
                ready_o <= 1'b1;
                buffer <= 1'b0;
            end else begin
                // No data is stored, ready for more input
                data_o <= 4'b0;
                valid_o <= 1'b0;
                ready_o <= 1'b1;
            end

            // Output data handling
            if (ready_i && buffer) begin
                // Forward stored data to the output
                data_o <= data_reg;
                valid_o <= 1'b1;
                ready_o <= 1'b0;
            end else begin
                // Data is not yet ready to be forwarded
                data_o <= 4'b0;
                valid_o <= 1'b0;
                ready_o <= 1'b1;
            end
        end
    end

endmodule

